    if aligned:
        entry_fvg = min(aligned, key=lambda f: abs(f["mid"] - current_price))
        entry_proxy = entry_fvg["top"]
        entry_note = f"iFVG zone {entry_fvg['bottom']:.2f}–{entry_fvg['top']:.2f} (enter at top)"

if entry_fvg is None:
